import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    min_penalty_time = float('inf')

    for i, customer in enumerate(unvisited_customers):
        travel_time = np.linalg.norm(np.array(customer) - np.array(cur_truck_pos)) / truck_speed
        arrival_time = current_time + travel_time

        if arrival_time > time_windows[i][1]:
            penalty_time = float('inf')
        elif arrival_time < time_windows[i][0]:
            penalty_time = time_windows[i][0] - current_time
        else:
            penalty_time = 0

        completion_time = max(arrival_time, time_windows[i][0]) + penalty_time
        if completion_time < min_penalty_time:
            min_penalty_time = completion_time
            best_node = i

    return best_node
